mapper.sql:
select arrayJoin(bitmapToArray(groupBitmapAndState(posts))) as postId from ( select bitmapBuild([number]) as posts from numbers(0)
union all select groupBitmapOrState(post_bitmap) as posts from ( select action_date, as post_bitmap from lofter.tag_fetch_tag_action_dd where dt = #{yesterday}
and action_date >= #{startDate} and action_date <= #{endDate} group by action_date ) t
union all select groupBitmapState(postId) as posts from url(#{postIdUrl}, CSV, 'postId UInt64')
union all select groupBitmapState(reinterpretAsUInt64(reverse(unhex(substring(extract(path(postLink), '(?:_).*'), 2))))) as posts from url(#{postLinkUrl}, CSV, 'postLink String')
union all select groupBitmapState(postId) as posts from lofter.tag_fetch_post_dd where dt = #{yesterday} and userId in (select userId from url(#{blogIdUrl}, CSV, 'userId UInt64')) and publish_date >= #{startDate} and publish_date <= #{endDate}
union all select groupBitmapState(postId) as posts from lofter.tag_fetch_post_dd where dt = #{yesterday} and blog_nickname in (select blogNickName from url(#{blogNickNameUrl}, CSV, 'blogNickName String')) and publish_date >= #{startDate} and publish_date <= #{endDate}
union all select groupBitmapState(postId) as posts from lofter.tag_fetch_post_dd where dt = #{yesterday} and blog_name in (select replace(domain(blogUrl), '.lofter.com', '') as blogName from url(#{blogNameUrl}, CSV, 'blogUrl String')) and publish_date >= #{startDate} and publish_date <= #{endDate}
) t

mapper.select:

select x.postId as postId, x.userId as userId, publish_date as publishDate, concat('https://', url) as postUrl, authenticate_names as authenticateNames, blog_nickname as blogNickName, blog_name as blogName,
    x.post_count_std as postNum, x.fans_std as beenFollowedUV, x.tags as tags, x.content_type as contentType, x.title as title, x.level as level,
    if(bitmapContains(forbid_post_bitmap, x.postId), '是', '否') as tagForbid,
    if(bitmapContains(gift_post_bitmap, x.postId), 1, 0) as returnGiftSet,
    y.shua_hot as shuaHot, y.hot as hot, y.commend_count as commendCount, y.praise_count as praiseCount, y.reproduce_count as reproduceCount, recommend_count as recommendCount,
    y.free_gift_uv as freeGiftUserCount, y.free_gift_pv as freeGiftCount, y.pay_gift_uv as payGiftUserCount, y.pay_gift_money_amount as payGiftAmount,
    x.post_main_content_type as postMainContentType,
    x.return_gift_plantype as returnGiftPlanType,
    toString(toDateTime(x.publishTime/1000)) as publishTime,
    if(x.recomStatus > 0, '人审通过', if(recomStatus < 0, '人审不通过', '人审等待')) as recomStatus,
    y.exposed_count as exposedCount,
    y.click_count as clickCount,
    (y.rec_exposed_count / y.exposed_count) as recTrafficRatio,
    (y.feed_rec_exposed_count/y.exposed_count) as feedRecTrafficRatio,
    (y.tag_rec_exposed_count/y.exposed_count) as tagRecTrafficRatio,
    (y.cold_start_rec_exposed_count/y.exposed_count) as coldStartTrafficRatio,
    if(x.is_premium > 0, '是', '否') as premium,
    x.pay_status as payStatus
from (
    select a.*
    from (
        select * from lofter.tag_fetch_post_dd
        where dt = #{yesterday}

    ) a join posts b on a.postId = b.postId
) x
left join post_period_data y on x.postId = y.postId



            order by multiIf(level = 'S', 'G', level = 'A', 'F', level = 'B', 'E', level = 'C', 'D', level = 'D', 'C', level = 'D*', 'B', 'A')
            ${sortOrder}


            order by ${sortField} ${sortOrder}



LIMIT #{limit} OFFSET #{offset}


select count(*)
from (
    select a.*
    from (
        select * from lofter.tag_fetch_post_dd
        where dt = #{yesterday}

    ) a join posts b on a.postId = b.postId
) x
left join post_period_data y on x.postId = y.postId
